UPDATE plants p
JOIN tmp_plants_excel t ON t.name = p.name
SET
  p.emoji = t.emoji,
  p.description = t.description,
  p.second_name = t.second_name,
  p.scientific_name = t.scientific_name,
  p.group_1 = t.group_1,
  p.group_2 = t.group_2,
  p.group_3 = t.group_3,
  p.habitat = t.habitat,
  p.photo = t.photo,
  p.nutrition = t.nutrition,
  p.agroecosystem_category = t.agroecosystem_category,
  p.longevity = t.longevity,
  p.remark_1 = t.remark_1,
  p.remark_2 = t.remark_2,
  p.remark_3 = t.remark_3,
  p.reproduction = t.reproduction,
  p.size = t.size,
  p.sources = t.sources,
  p.ideal_temperature_c = t.ideal_temperature_c,
  p.optimal_ph = t.optimal_ph,
  p.ecosystem_role = t.ecosystem_role,
  p.geographic_origin = t.geographic_origin,
  p.human_utility = t.human_utility,
  p.harvest_part = t.harvest_part,
  p.planting_recommendations = t.planting_recommendations,
  p.preferred_nutrients = t.preferred_nutrients,
  p.photo_species = t.photo_species,
  p.photo_leaf = t.photo_leaf,
  p.photo_flower = t.photo_flower,
  p.photo_fruit = t.photo_fruit,
  p.photo_harvest_part = t.photo_harvest_part;

INSERT INTO plants (name, emoji, description, second_name, scientific_name, group_1, group_2, group_3, habitat, photo, nutrition, agroecosystem_category, longevity, remark_1, remark_2, remark_3, reproduction, size, sources, ideal_temperature_c, optimal_ph, ecosystem_role, geographic_origin, human_utility, harvest_part, planting_recommendations, preferred_nutrients, photo_species, photo_leaf, photo_flower, photo_fruit, photo_harvest_part)
SELECT t.name, t.emoji, t.description, t.second_name, t.scientific_name, t.group_1, t.group_2, t.group_3, t.habitat, t.photo, t.nutrition, t.agroecosystem_category, t.longevity, t.remark_1, t.remark_2, t.remark_3, t.reproduction, t.size, t.sources, t.ideal_temperature_c, t.optimal_ph, t.ecosystem_role, t.geographic_origin, t.human_utility, t.harvest_part, t.planting_recommendations, t.preferred_nutrients, t.photo_species, t.photo_leaf, t.photo_flower, t.photo_fruit, t.photo_harvest_part
FROM tmp_plants_excel t
LEFT JOIN plants p ON p.name = t.name
WHERE p.id IS NULL;

